SELECT AVG(
    (julianday(tt.alighting_time) - julianday(tt.boarding_time)) * 1440
) AS average_trip_duration
FROM trips t
JOIN trips_taken tt ON t.trip_id = tt.trip_id
WHERE t.route_id = '1';

SELECT COUNT(passenger_id) AS total_passengers
FROM trips_taken
WHERE trip_id = '0';

SELECT trip_id, delay
FROM realtime_schedules
WHERE realtime_status = 'delayed';
